import{_ as e,o as r,c as a,ag as s}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Network Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"theory/networks/network-concepts.md","filePath":"theory/networks/network-concepts.md"}'),n={name:"theory/networks/network-concepts.md"};function o(d,t,i,l,c,h){return r(),a("div",null,[...t[0]||(t[0]=[s(`<h1 id="network-concepts" tabindex="-1">Network Concepts <a class="header-anchor" href="#network-concepts" aria-label="Permalink to &quot;Network Concepts&quot;">​</a></h1><p>Standalone computers are powerful — networked computers are transformational. A network lets computers share resources, communicate, and access the internet. Understanding networks is foundational to every topic in the communication and internet sections of Paper 2.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10+</p><p>Basic network concepts (what is a network, advantages, types) are introduced in Grade 10. Hardware, topologies, protocols, and security extend through Grade 11 and 12.</p></div><hr><h2 id="what-is-a-computer-network" tabindex="-1">What is a Computer Network? <a class="header-anchor" href="#what-is-a-computer-network" aria-label="Permalink to &quot;What is a Computer Network?&quot;">​</a></h2><p>A <strong>computer network</strong> is two or more computers connected together to share resources and communicate.</p><p><strong>Resources that can be shared:</strong></p><ul><li>Files and data</li><li>Printers and scanners</li><li>Internet connection</li><li>Software applications</li><li>Storage space</li></ul><hr><h2 id="why-use-a-network" tabindex="-1">Why Use a Network? <a class="header-anchor" href="#why-use-a-network" aria-label="Permalink to &quot;Why Use a Network?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Advantage</th><th>Explanation</th></tr></thead><tbody><tr><td><strong>Resource sharing</strong></td><td>One printer or internet connection serves many computers</td></tr><tr><td><strong>Data sharing</strong></td><td>Files can be accessed from any computer on the network</td></tr><tr><td><strong>Communication</strong></td><td>Email, messaging, video calls between users</td></tr><tr><td><strong>Centralised management</strong></td><td>IT can update software and manage all computers from one place</td></tr><tr><td><strong>Backup</strong></td><td>Data can be backed up automatically to a central server</td></tr><tr><td><strong>Cost efficiency</strong></td><td>Shared resources reduce the need for individual peripherals</td></tr></tbody></table><p><strong>Disadvantages:</strong></p><ul><li>Security risks — one compromised device can affect all</li><li>Setup and maintenance costs</li><li>If the server fails, the whole network is affected</li><li>Requires technical expertise to manage</li></ul><hr><h2 id="network-models" tabindex="-1">Network Models <a class="header-anchor" href="#network-models" aria-label="Permalink to &quot;Network Models&quot;">​</a></h2><h3 id="client-server-network" tabindex="-1">Client-Server Network <a class="header-anchor" href="#client-server-network" aria-label="Permalink to &quot;Client-Server Network&quot;">​</a></h3><p>A <strong>dedicated server</strong> provides services to client computers.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client 1 ──┐</span></span>
<span class="line"><span>Client 2 ──┤── Server (file, print, web, email)</span></span>
<span class="line"><span>Client 3 ──┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><table tabindex="0"><thead><tr><th>Feature</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Server</strong></td><td>Powerful computer dedicated to network services</td></tr><tr><td><strong>Clients</strong></td><td>Workstations that request services from the server</td></tr><tr><td><strong>Control</strong></td><td>Centralised — IT admin controls access from one place</td></tr><tr><td><strong>Security</strong></td><td>High — centralised authentication</td></tr><tr><td><strong>Scalability</strong></td><td>Can add more clients easily</td></tr><tr><td><strong>Dependency</strong></td><td>If server fails, clients lose network access</td></tr><tr><td><strong>Cost</strong></td><td>High — server hardware + network OS + maintenance</td></tr><tr><td><strong>Used in</strong></td><td>Schools, offices, businesses, data centres</td></tr></tbody></table><h3 id="peer-to-peer-p2p-network" tabindex="-1">Peer-to-Peer (P2P) Network <a class="header-anchor" href="#peer-to-peer-p2p-network" aria-label="Permalink to &quot;Peer-to-Peer (P2P) Network&quot;">​</a></h3><p>All computers are <strong>equal</strong> — any device can be both client and server.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Computer A ── Computer B ── Computer C</span></span>
<span class="line"><span>     └──────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><table tabindex="0"><thead><tr><th>Feature</th><th>Detail</th></tr></thead><tbody><tr><td><strong>No dedicated server</strong></td><td>All computers share resources directly</td></tr><tr><td><strong>Control</strong></td><td>Decentralised — each user controls their own computer</td></tr><tr><td><strong>Security</strong></td><td>Lower — harder to enforce consistent security</td></tr><tr><td><strong>Scalability</strong></td><td>Not suitable for large networks (slow and complex)</td></tr><tr><td><strong>Cost</strong></td><td>Low — no server needed</td></tr><tr><td><strong>Used in</strong></td><td>Home networks, small offices (under 10 computers)</td></tr></tbody></table><hr><h2 id="network-types-by-size" tabindex="-1">Network Types by Size <a class="header-anchor" href="#network-types-by-size" aria-label="Permalink to &quot;Network Types by Size&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Full Name</th><th>Range</th><th>Example</th></tr></thead><tbody><tr><td><strong>PAN</strong></td><td>Personal Area Network</td><td>~1–10 metres</td><td>Bluetooth headset ↔ phone</td></tr><tr><td><strong>LAN</strong></td><td>Local Area Network</td><td>Building or campus</td><td>School computer lab</td></tr><tr><td><strong>MAN</strong></td><td>Metropolitan Area Network</td><td>City or town</td><td>City-wide Wi-Fi system</td></tr><tr><td><strong>WAN</strong></td><td>Wide Area Network</td><td>Country or continent</td><td>Bank branches linked nationally</td></tr><tr><td><strong>Internet</strong></td><td>Global WAN</td><td>Worldwide</td><td>The internet</td></tr><tr><td><strong>HAN</strong></td><td>Home Area Network</td><td>One home</td><td>Home router network</td></tr></tbody></table><h3 id="lan-characteristics" tabindex="-1">LAN Characteristics <a class="header-anchor" href="#lan-characteristics" aria-label="Permalink to &quot;LAN Characteristics&quot;">​</a></h3><ul><li>High speed (100 Mbps to 10 Gbps)</li><li>Low cost — short cable distances</li><li>Private — owned and managed by the organisation</li><li>Can be wired (Ethernet) or wireless (Wi-Fi)</li></ul><h3 id="wan-characteristics" tabindex="-1">WAN Characteristics <a class="header-anchor" href="#wan-characteristics" aria-label="Permalink to &quot;WAN Characteristics&quot;">​</a></h3><ul><li>Connects geographically distant networks</li><li>Lower speed and higher cost than LAN</li><li>Typically uses public infrastructure (leased lines, internet, satellite)</li><li>Managed by ISPs (Internet Service Providers)</li></ul><hr><h2 id="wired-vs-wireless-networks" tabindex="-1">Wired vs Wireless Networks <a class="header-anchor" href="#wired-vs-wireless-networks" aria-label="Permalink to &quot;Wired vs Wireless Networks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Wired (Ethernet)</th><th>Wireless (Wi-Fi)</th></tr></thead><tbody><tr><td>Speed</td><td>Up to 10 Gbps</td><td>Up to 9.6 Gbps (Wi-Fi 6)</td></tr><tr><td>Reliability</td><td>Very high — no interference</td><td>Lower — can drop, interference possible</td></tr><tr><td>Security</td><td>Higher — physical access needed</td><td>Lower — signals travel through walls</td></tr><tr><td>Installation</td><td>Cables must be run</td><td>No cables needed</td></tr><tr><td>Mobility</td><td>Fixed — cable length limits movement</td><td>Full mobility within coverage area</td></tr><tr><td>Cost</td><td>Cable + ports + installation</td><td>WAP + no cable installation</td></tr><tr><td>Best for</td><td>Servers, labs, desktop PCs</td><td>Laptops, phones, tablets</td></tr></tbody></table><hr><h2 id="network-hardware-summary" tabindex="-1">Network Hardware Summary <a class="header-anchor" href="#network-hardware-summary" aria-label="Permalink to &quot;Network Hardware Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Device</th><th>Function</th></tr></thead><tbody><tr><td><strong>NIC (Network Interface Card)</strong></td><td>Hardware in each computer enabling network connection</td></tr><tr><td><strong>Router</strong></td><td>Connects networks together; directs data between networks; provides IP addresses (DHCP)</td></tr><tr><td><strong>Switch</strong></td><td>Connects devices on the SAME network; sends data only to intended device</td></tr><tr><td><strong>Hub</strong></td><td>Like a switch but broadcasts to all devices — less efficient (mostly outdated)</td></tr><tr><td><strong>Modem</strong></td><td>Converts digital to analogue for phone-line transmission (and back)</td></tr><tr><td><strong>Wireless Access Point (WAP)</strong></td><td>Extends wireless coverage; connects wireless devices to wired network</td></tr><tr><td><strong>Repeater / Range extender</strong></td><td>Boosts signal to extend coverage distance</td></tr><tr><td><strong>Bridge</strong></td><td>Connects two network segments</td></tr><tr><td><strong>Firewall</strong></td><td>Hardware or software filtering incoming/outgoing network traffic for security</td></tr></tbody></table><hr><h2 id="intranet-vs-extranet-vs-internet" tabindex="-1">Intranet vs Extranet vs Internet <a class="header-anchor" href="#intranet-vs-extranet-vs-internet" aria-label="Permalink to &quot;Intranet vs Extranet vs Internet&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Intranet</th><th>Extranet</th><th>Internet</th></tr></thead><tbody><tr><td><strong>Access</strong></td><td>Internal users only</td><td>Internal + authorised external users</td><td>Anyone</td></tr><tr><td><strong>Example</strong></td><td>Company internal website</td><td>Supplier accessing company inventory system</td><td>World Wide Web</td></tr><tr><td><strong>Security</strong></td><td>High — inside firewall</td><td>Medium — controlled external access</td><td>Lower — public</td></tr></tbody></table><hr><h2 id="network-topologies" tabindex="-1">Network Topologies <a class="header-anchor" href="#network-topologies" aria-label="Permalink to &quot;Network Topologies&quot;">​</a></h2><p>The <strong>topology</strong> is the physical or logical arrangement of computers and cables in a network.</p><h3 id="star-topology" tabindex="-1">Star Topology <a class="header-anchor" href="#star-topology" aria-label="Permalink to &quot;Star Topology&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>      PC</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span>PC ─ Switch ─ PC</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span>      PC</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><ul><li>All devices connect to a <strong>central switch or hub</strong></li><li><strong>Most common in modern networks</strong></li></ul><table tabindex="0"><thead><tr><th>Advantage</th><th>Disadvantage</th></tr></thead><tbody><tr><td>If one cable fails, only that device is affected</td><td>If the central switch fails, the whole network fails</td></tr><tr><td>Easy to add new devices</td><td>More cable required</td></tr><tr><td>Easy to troubleshoot</td><td>Central switch is a single point of failure</td></tr></tbody></table><h3 id="bus-topology" tabindex="-1">Bus Topology <a class="header-anchor" href="#bus-topology" aria-label="Permalink to &quot;Bus Topology&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PC ─── PC ─── PC ─── PC ─── PC</span></span>
<span class="line"><span>│                             │</span></span>
<span class="line"><span>Terminator                  Terminator</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li>All devices connect to a single cable (the bus)</li><li><strong>Largely obsolete</strong></li></ul><table tabindex="0"><thead><tr><th>Advantage</th><th>Disadvantage</th></tr></thead><tbody><tr><td>Less cable needed</td><td>If the main cable breaks, the whole network fails</td></tr><tr><td>Easy and cheap to set up</td><td>Performance degrades as more devices added</td></tr></tbody></table><h3 id="ring-topology" tabindex="-1">Ring Topology <a class="header-anchor" href="#ring-topology" aria-label="Permalink to &quot;Ring Topology&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    PC</span></span>
<span class="line"><span>   /  \\</span></span>
<span class="line"><span> PC    PC</span></span>
<span class="line"><span>   \\  /</span></span>
<span class="line"><span>    PC</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><ul><li>Devices form a closed loop; data travels in one direction</li></ul><table tabindex="0"><thead><tr><th>Advantage</th><th>Disadvantage</th></tr></thead><tbody><tr><td>Equal access for all devices</td><td>One break brings down the whole network</td></tr><tr><td>Data flows in one direction (no collisions)</td><td>Difficult to troubleshoot</td></tr></tbody></table><h3 id="mesh-topology" tabindex="-1">Mesh Topology <a class="header-anchor" href="#mesh-topology" aria-label="Permalink to &quot;Mesh Topology&quot;">​</a></h3><p>Every device connects to every other device:</p><table tabindex="0"><thead><tr><th>Advantage</th><th>Disadvantage</th></tr></thead><tbody><tr><td>Very reliable — multiple paths for data</td><td>Very expensive — many cables</td></tr><tr><td>Used in WANs and internet backbone</td><td>Complex to manage</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">Exam Tip</p><p>Know <strong>two advantages AND two disadvantages</strong> of star, bus, and ring. Star is almost always the correct choice for a modern LAN — be able to explain why.</p></div><hr><h2 id="client-server-vs-p2p-—-summary" tabindex="-1">Client-Server vs P2P — Summary <a class="header-anchor" href="#client-server-vs-p2p-—-summary" aria-label="Permalink to &quot;Client-Server vs P2P — Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Criterion</th><th>Client-Server</th><th>Peer-to-Peer</th></tr></thead><tbody><tr><td>Number of computers</td><td>Many (enterprise)</td><td>Few (&lt;10 for practicality)</td></tr><tr><td>Dedicated server needed?</td><td>Yes</td><td>No</td></tr><tr><td>Cost</td><td>High</td><td>Low</td></tr><tr><td>Security</td><td>Centralised, high</td><td>Decentralised, low</td></tr><tr><td>Performance</td><td>Consistent</td><td>Degrades as more added</td></tr><tr><td>Administration</td><td>From one server</td><td>Each user manages own PC</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Network</strong></td><td>Two or more computers connected to share resources</td></tr><tr><td><strong>LAN</strong></td><td>Local Area Network — within a building or campus</td></tr><tr><td><strong>WAN</strong></td><td>Wide Area Network — across cities, countries</td></tr><tr><td><strong>Client</strong></td><td>Computer that requests services from a server</td></tr><tr><td><strong>Server</strong></td><td>Dedicated computer providing network services</td></tr><tr><td><strong>P2P</strong></td><td>Peer-to-Peer — all computers are equal with no dedicated server</td></tr><tr><td><strong>Topology</strong></td><td>Physical or logical arrangement of network devices</td></tr><tr><td><strong>Star topology</strong></td><td>All devices connect to a central switch</td></tr><tr><td><strong>Bus topology</strong></td><td>All devices share one cable</td></tr><tr><td><strong>Router</strong></td><td>Connects networks; directs data between them</td></tr><tr><td><strong>Switch</strong></td><td>Connects devices on the same network efficiently</td></tr><tr><td><strong>Intranet</strong></td><td>Private internal network using web technologies</td></tr><tr><td><strong>Extranet</strong></td><td>Intranet with controlled access for external authorised users</td></tr><tr><td><strong>Firewall</strong></td><td>Security device/software that filters network traffic</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;Give TWO advantages of a LAN&quot;</strong> — resource sharing, communication, centralised management, cost saving</p></li><li><p><strong>&quot;Compare client-server and P2P networks&quot;</strong> — dedicate at least two criteria: cost, security, scalability, server dependency</p></li><li><p><strong>&quot;Draw and describe the star topology. Give one advantage and one disadvantage.&quot;</strong> — can draw a simple diagram; central switch; advantage: one cable failure doesn&#39;t down whole network; disadvantage: switch failure takes out all</p></li><li><p><strong>&quot;What is the difference between a router and a switch?&quot;</strong> — router connects networks and routes data between them; switch connects devices on the same network</p></li><li><p><strong>&quot;Give ONE example of an intranet use in a school&quot;</strong> — school&#39;s internal website with timetables, notices, and results accessible only from school computers</p></li></ol></div>`,67)])])}const g=e(n,[["render",o]]);export{u as __pageData,g as default};
